import { ref, onMounted } from 'vue'
import profile from '@/api/profile'
import { ElMessage } from 'element-plus'

export function useModules() {
  const loading = ref(false)
  const modules = ref([])

  const fetchModulesData = async () => {
    loading.value = true
    try {
      const response = await profile.getData()
      if (response.data?.code === 200) {
        const data = response.data.data
        modules.value = [
          { type: 'basic_info', data: data.basic_info || {} },
          { type: 'job_intention', data: data.job_intention || {} },
          { type: 'work_experience', data: data.work_experience || [] },
          { type: 'education', data: data.education || [] },
          { type: 'project', data: data.project || [] },
          { type: 'skill', data: data.skill || [] },
          { type: 'certificate', data: data.certificate || [] },
          { type: 'language', data: data.language || [] },
          { type: 'portfolio', data: data.portfolio || [] },
          { type: 'social_link', data: data.social_link || [] }
        ]
        console.log('模块数据更新:', modules.value)
      }
    } catch (error) {
      console.error('获取模块数据失败:', error)
      ElMessage.error('获取模块数据失败')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    modules,
    fetchModulesData
  }
}
